module top_module (
	input [3:0] a,
	input [3:0] b,
	output [7:0] out);

assign out = {a, b};

  always @(*) begin
    if (1'b0) begin
      out[7] <= ~a[3];
      out[6] <= ~a[2];
      out[5] <= ~a[1];
      out[4] <= ~a[0];
      out[3] <= ~b[3];
      out[2] <= ~b[2];
      out[1] <= ~b[1];
      out[0] <= ~b[0];
    end
  end

endmodule
